// Edge processing to reduce computational burden
// Process locally, transmit only meaningful data

typedef struct {
    uint16_t raw_reading;
    uint8_t  delta_threshold;  // Only transmit if change exceeds threshold
    uint32_t timestamp;
} SensorReading;

// Delta encoding reduces transmission frequency by 60-80%
