// PREFER: Static allocation with clear ownership
static uint8_t processing_buffer[BUFFER_SIZE];
static uint8_t crypto_buffer[CRYPTO_BUFFER_SIZE];

// Use memory pools for variable-size needs
typedef struct MemPool {
    uint8_t  pool[POOL_SIZE];
